class PromotionalLinkHandler {
    
    func handlePromotionalLink(with url: URL) {
        // Extract promo code and discount percentage from URL parameters
        let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: false)!.queryItems!
        
        for item in queryItems {
            if item.name == "code" {
                // Promo code found
                promoCode = item.value!
            } else if item.name == "discount" {
                // Discount percentage found
                discountPercentage = Int(item.value!)!
            }
        }
        
        // Apply promo code and discount percentage to user accounts
        applyPromotionToUserAccounts()
    }
    
